/**
 * 顺序执行迁移 SQL，确保 D1 在表结构变更场景下按预期串行落库。
 * @param db 当前迁移事务中的数据库实例
 * @param statements 待执行的 SQL 语句
 */
async function runStatements(
  db: MigrateUpArgs['db'] | MigrateDownArgs['db'],
  statements: readonly string[],
): Promise<void> {
  for (const statement of statements) {
    // 使用原始 SQL 保持 Payload 生成迁移的执行语义，避免模板字符串转义影响语句内容。
    await db.run(sql.raw(statement))
  }
}

/**
 * 执行营销内容模型收敛迁移。
 * 先应用纯结构变更，再预留自定义迁移插槽，最后继续执行剩余语句。
 * @param args Payload D1 迁移上下文
 */
export async function up({ db }: MigrateUpArgs): Promise<void> {
  await runStatements(db, UP_STATEMENTS.slice(0, STRUCTURE_ONLY_UP_STATEMENT_COUNT))

  /* __CUSTOM_MIGRATION_CODE__ */

  await runStatements(db, UP_STATEMENTS.slice(STRUCTURE_ONLY_UP_STATEMENT_COUNT))
}

/**
 * 回滚营销内容模型收敛迁移。
 * @param args Payload D1 迁移上下文
 */
export async function down({ db }: MigrateDownArgs): Promise<void> {
  await runStatements(db, DOWN_STATEMENTS)
}
